mapper.update:
UPDATE user_coupon
SET status = #{status}
WHERE user_coupon_id = #{userCouponId} AND status = false

mapper.select:
SELECT biz_id AS bizId, 2 AS behaviorType, UNIX_TIMESTAMP(get_time) * 1000 AS timestamp FROM user_coupon
WHERE user_id = #{userId}
ORDER BY get_time DESC
LIMIT #{limit}
